import { useEffect, useState, useRef, useCallback } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { useForm } from "react-hook-form";
import { MapContainer, TileLayer, Marker, Popup } from "react-leaflet";
import L from "leaflet";
import "leaflet/dist/leaflet.css";
import {
    FaMapMarkerAlt,
    FaCalendarAlt,
    FaUsers,
    FaPen,
    FaTrash,
    FaCloudSun,
    FaStar,
} from "react-icons/fa";
import toast from "react-hot-toast";

import { useAuth } from "../../context/AuthContext";
import {
    getTripById,
    updateTrip,
    deleteTrip,
    getWeatherData,
    addExpense,
    deleteExpense,
    getReviews,
    addReview,
} from "../../services/tripService";
import styles from "./TripDetails.module.css";

// Fix default marker icon for react-leaflet
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
    iconRetinaUrl: "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-icon-2x.png",
    iconUrl: "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-icon.png",
    shadowUrl: "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-shadow.png",
});

const TripDetails = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const { user } = useAuth();

    const [loading, setLoading] = useState(true);
    const [data, setData] = useState(null);
    const [weather, setWeather] = useState(null);
    const [weatherLoading, setWeatherLoading] = useState(true);
    const [reviews, setReviews] = useState([]);
    const [newRating, setNewRating] = useState(5);
    const [isEditing, setIsEditing] = useState(false);
    const [coords, setCoords] = useState(null); // null = not yet geocoded

    // Forms
    const {
        register: registerExpense,
        handleSubmit: handleSubmitExpense,
        reset: resetExpense,
        formState: { isSubmitting: addingExp },
    } = useForm();

    const {
        register: registerEdit,
        handleSubmit: handleSubmitEdit,
        reset: resetEdit,
        formState: { isSubmitting: savingTrip },
    } = useForm();

    const {
        register: registerReview,
        handleSubmit: handleSubmitReview,
        reset: resetReview,
    } = useForm();

    // Fetch Details & Weather
    const loadAllDetails = useCallback(async () => {
        try {
            const details = await getTripById(id);
            setData(details);
            resetEdit({
                destination: details.trip.destination,
                city: details.trip.city,
                country: details.trip.country,
                budget: details.trip.budget,
                startDate: details.trip.startDate.split("T")[0],
                endDate: details.trip.endDate.split("T")[0],
                transportation: details.trip.transportation,
                description: details.trip.description,
                travelers: details.trip.travelers,
                status: details.trip.status,
                isPublic: details.trip.isPublic,
            });

            // Fetch Weather
            setWeatherLoading(true);
            try {
                const weatherData = await getWeatherData(details.trip.city);
                setWeather(weatherData.weather);
            } catch (weaErr) {
                console.warn("Could not load weather details:", weaErr.message);
                setWeather(null);
            } finally {
                setWeatherLoading(false);
            }

            // Fetch Reviews
            if (details.trip.isPublic) {
                try {
                    const reviewData = await getReviews(id);
                    setReviews(reviewData.reviews);
                } catch (revErr) {
                    console.warn("Could not load reviews:", revErr.message);
                }
            }

            // Geocode: city + country → lat/lng using Nominatim (OpenStreetMap)
            let lat = 48.8566; // Paris fallback
            let lng = 2.3522;
            try {
                const searchQ = `${details.trip.city}, ${details.trip.country}`;
                const geoRes = await fetch(
                    `https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(searchQ)}&limit=1`,
                    {
                        headers: {
                            "Accept-Language": "en",
                            "User-Agent": "JourneyFly-App/1.0",
                        },
                    }
                );
                const geoData = await geoRes.json();
                if (geoData && geoData.length > 0) {
                    lat = parseFloat(geoData[0].lat);
                    lng = parseFloat(geoData[0].lon);
                } else {
                    console.warn(`No geocoding result for: ${searchQ}`);
                }
            } catch (geoErr) {
                console.warn("Geocoding failed:", geoErr.message);
            }

            setCoords([lat, lng]);
        } catch (error) {
            toast.error(error.message || "Failed to load trip details.");
            navigate("/trips");
        } finally {
            setLoading(false);
        }
    }, [id, navigate, resetEdit]);

    useEffect(() => {
        loadAllDetails();
    }, [loadAllDetails]);

    // Handle Delete Trip
    const handleDelete = async () => {
        if (!window.confirm("Are you sure you want to delete this trip and all its expenses?")) return;

        try {
            await deleteTrip(id);
            toast.success("Trip deleted successfully.");
            navigate("/trips");
        } catch (error) {
            toast.error(error.message);
        }
    };

    // Handle Edit Trip Submission
    const handleEditSubmit = async (formDataFields) => {
        const formData = new FormData();
        Object.keys(formDataFields).forEach((key) => {
            formData.append(key, formDataFields[key]);
        });

        const fileInput = document.getElementById("editTripImage");
        if (fileInput?.files?.[0]) {
            formData.append("tripImage", fileInput.files[0]);
        }

        try {
            await updateTrip(id, formData);
            toast.success("Trip logs updated successfully!");
            setIsEditing(false);
            loadAllDetails();
        } catch (error) {
            toast.error(error.message);
        }
    };

    // Add Expense
    const handleAddExpense = async (expData) => {
        try {
            const res = await addExpense({
                tripId: id,
                category: expData.category,
                amount: expData.amount,
                description: expData.description,
                date: expData.date,
            });
            toast.success("Expense registered! 💰");
            resetExpense();
            loadAllDetails();

            // Notify if budget is exceeded
            if (res.summary.totalExpense > res.summary.totalBudget) {
                toast.error("⚠️ Budget alert! Total expenses exceed trip budget.");
            }
        } catch (error) {
            toast.error(error.message);
        }
    };

    // Remove Expense
    const handleRemoveExpense = async (expenseId) => {
        if (!window.confirm("Remove this expense entry?")) return;

        try {
            await deleteExpense(expenseId);
            toast.success("Expense entry removed.");
            loadAllDetails();
        } catch (error) {
            toast.error(error.message);
        }
    };

    // Submit Review
    const handleAddReview = async (reviewData) => {
        try {
            await addReview(id, {
                rating: newRating,
                comment: reviewData.comment,
            });
            toast.success("Review submitted! ⭐");
            resetReview();
            setNewRating(5);
            loadAllDetails();
        } catch (error) {
            toast.error(error.message);
        }
    };

    if (loading) {
        return (
            <div className="global-loader-container">
                <div className="global-loader"></div>
            </div>
        );
    }

    const { trip, expenses, summary } = data;
    const isOwner = String(trip.user._id || trip.user) === user?.id;

    // Safe percentage calculation (avoid divide by zero)
    const totalBudget = summary.totalBudget > 0 ? summary.totalBudget : 1;
    const percentSpent = Math.min((summary.totalExpense / totalBudget) * 100, 100);

    return (
        <div className={styles.container}>
            {/* Cover Hero section */}
            <div className={styles.hero}>
                <img
                    src={trip.tripImage || "https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800"}
                    alt={trip.destination}
                    className={styles.heroImage}
                />
                <div className={styles.heroOverlay}>
                    <h1>{trip.destination}</h1>
                    <div className={styles.heroLocation}>
                        <FaMapMarkerAlt /> {trip.city}, {trip.country}
                    </div>
                </div>

                {isOwner && (
                    <div className={styles.actionRow}>
                        <button className={`${styles.actionBtn} ${styles.editBtn}`} onClick={() => setIsEditing(!isEditing)}>
                            <FaPen /> {isEditing ? "Close Edit" : "Edit Trip"}
                        </button>
                        <button className={`${styles.actionBtn} ${styles.deleteBtn}`} onClick={handleDelete}>
                            <FaTrash /> Delete Trip
                        </button>
                    </div>
                )}
            </div>

            {/* EDIT PLAN MODE */}
            {isEditing && (
                <div className={styles.card} style={{ border: "1px solid var(--primary)", animation: "fadeIn 0.3s" }}>
                    <h2>✏️ Edit Trip Details</h2>
                    <form onSubmit={handleSubmitEdit(handleEditSubmit)} className={styles.formGrid}>
                        <div className={styles.inputGroup}>
                            <label>Destination Title</label>
                            <input type="text" {...registerEdit("destination", { required: true })} />
                        </div>
                        <div className={styles.inputGroup}>
                            <label>City</label>
                            <input type="text" {...registerEdit("city", { required: true })} />
                        </div>
                        <div className={styles.inputGroup}>
                            <label>Country</label>
                            <input type="text" {...registerEdit("country", { required: true })} />
                        </div>
                        <div className={styles.inputGroup}>
                            <label>Budget ($)</label>
                            <input type="number" {...registerEdit("budget", { required: true })} />
                        </div>
                        <div className={styles.inputGroup}>
                            <label>Start Date</label>
                            <input type="date" {...registerEdit("startDate", { required: true })} />
                        </div>
                        <div className={styles.inputGroup}>
                            <label>End Date</label>
                            <input type="date" {...registerEdit("endDate", { required: true })} />
                        </div>
                        <div className={styles.inputGroup}>
                            <label>Transportation</label>
                            <select {...registerEdit("transportation")}>
                                <option value="Flight">✈️ Flight</option>
                                <option value="Train">🚄 Train</option>
                                <option value="Bus">🚌 Bus</option>
                                <option value="Car">🚗 Car</option>
                                <option value="Other">🎒 Other</option>
                            </select>
                        </div>
                        <div className={styles.inputGroup}>
                            <label>Travelers</label>
                            <input type="number" min="1" {...registerEdit("travelers", { required: true })} />
                        </div>
                        <div className={styles.inputGroup}>
                            <label>Status</label>
                            <select {...registerEdit("status")}>
                                <option value="Upcoming">Upcoming</option>
                                <option value="Completed">Completed</option>
                                <option value="Cancelled">Cancelled</option>
                            </select>
                        </div>
                        <div className={styles.inputGroup}>
                            <label>Cover Image (Optional)</label>
                            <input type="file" id="editTripImage" accept="image/*" />
                        </div>
                        <div className={`${styles.inputGroup} ${styles.fullWidth}`}>
                            <label>Description / Notes</label>
                            <textarea {...registerEdit("description")} />
                        </div>
                        <div className={`${styles.inputGroup} ${styles.fullWidth}`}>
                            <label className={styles.checkboxLabel}>
                                <input type="checkbox" {...registerEdit("isPublic")} />
                                Make this trip Public (allows wishlist and reviews)
                            </label>
                        </div>
                        <div className={styles.fullWidth}>
                            <button type="submit" className={styles.submitBtn} disabled={savingTrip}>
                                {savingTrip ? "Saving Changes..." : "Update Trip Details"}
                            </button>
                        </div>
                    </form>
                </div>
            )}

            {/* Content grid details */}
            <div className={styles.detailsGrid}>
                {/* Left side: Information, Map, Expenses, Reviews */}
                <div>
                    {/* 1. Trip details */}
                    <div className={styles.card}>
                        <h2>ℹ️ Itinerary Overview</h2>
                        <div className={styles.infoGrid}>
                            <div className={styles.infoBlock}>
                                <h4>Transportation</h4>
                                <p>{trip.transportation === "Flight" ? "✈️ Flight" :
                                    trip.transportation === "Train" ? "🚄 Train" :
                                    trip.transportation === "Bus" ? "🚌 Bus" :
                                    trip.transportation === "Car" ? "🚗 Car" : "🎒 Other"}</p>
                            </div>
                            <div className={styles.infoBlock}>
                                <h4>Dates</h4>
                                <p>
                                    <FaCalendarAlt /> {new Date(trip.startDate).toLocaleDateString()} -{" "}
                                    {new Date(trip.endDate).toLocaleDateString()}
                                </p>
                            </div>
                            <div className={styles.infoBlock}>
                                <h4>Travelers</h4>
                                <p>
                                    <FaUsers /> {trip.travelers} {trip.travelers > 1 ? "people" : "person"}
                                </p>
                            </div>
                            <div className={styles.infoBlock}>
                                <h4>Planned by</h4>
                                <p style={{ display: "flex", alignItems: "center", gap: "5px" }}>
                                    <img
                                        src={trip.user.avatar || "https://cdn-icons-png.flaticon.com/512/3135/3135715.png"}
                                        alt="Avatar"
                                        style={{ width: "20px", height: "20px", borderRadius: "50%" }}
                                    />
                                    {trip.user.fullName}
                                </p>
                            </div>
                        </div>

                        {trip.description && (
                            <div style={{ marginTop: "20px", borderTop: "1px solid var(--border)", paddingTop: "15px" }}>
                                <h4>Trip Description / Notes:</h4>
                                <p className={styles.description}>{trip.description}</p>
                            </div>
                        )}
                    </div>

                    {/* 2. Interactive Map — uses react-leaflet, shows actual searched city */}
                    <div className={styles.card}>
                        <h2>📍 Route Map — {trip.city}, {trip.country}</h2>
                        {coords ? (
                            <MapContainer
                                key={`${coords[0]}-${coords[1]}`}
                                center={coords}
                                zoom={10}
                                className={styles.mapWrapper}
                                style={{ height: "320px", width: "100%", borderRadius: "10px" }}
                            >
                                <TileLayer
                                    url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
                                    attribution="&copy; <a href='https://www.openstreetmap.org/copyright'>OpenStreetMap</a>"
                                />
                                <Marker position={coords}>
                                    <Popup>
                                        <strong>{trip.city}</strong><br />{trip.country}
                                    </Popup>
                                </Marker>
                            </MapContainer>
                        ) : (
                            <div className={styles.mapWrapper} style={{ display: "flex", alignItems: "center", justifyContent: "center", background: "var(--border)", borderRadius: "10px" }}>
                                <p style={{ color: "var(--subText)" }}>Loading map...</p>
                            </div>
                        )}
                    </div>

                    {/* 3. Expense tracker */}
                    <div className={styles.card}>
                        <h2>💰 Budget & Expense Tracker</h2>

                        <div className={styles.budgetTracker}>
                            <div style={{ display: "flex", justifyContent: "space-between", fontWeight: "600" }}>
                                <span>Budget Utilization</span>
                                <span>{summary.totalBudget > 0 ? Math.round((summary.totalExpense / summary.totalBudget) * 100) : 0}%</span>
                            </div>
                            <div className={styles.progressBar}>
                                <div
                                    className={`${styles.progressFill} ${summary.totalExpense > summary.totalBudget ? styles.progressWarning : ""}`}
                                    style={{ width: `${percentSpent}%` }}
                                ></div>
                            </div>
                            <div className={styles.budgetStats}>
                                <div>Total Budget: <span>${summary.totalBudget.toLocaleString()}</span></div>
                                <div>Total Spent: <span>${summary.totalExpense.toLocaleString()}</span></div>
                                <div>Remaining: <span style={{ color: summary.remainingBudget < 0 ? "#ef4444" : "#10b981" }}>
                                    ${summary.remainingBudget.toLocaleString()}
                                </span></div>
                            </div>
                        </div>

                        {/* Add Expense Form (Owner Only) */}
                        {isOwner && (
                            <form onSubmit={handleSubmitExpense(handleAddExpense)} className={styles.formGrid} style={{ marginTop: "25px", borderTop: "1px solid var(--border)", paddingTop: "20px" }}>
                                <div className={styles.inputGroup}>
                                    <label>Category</label>
                                    <select {...registerExpense("category", { required: true })}>
                                        <option value="Food">🍽️ Food</option>
                                        <option value="Hotel">🏨 Hotel</option>
                                        <option value="Fuel">⛽ Fuel</option>
                                        <option value="Shopping">🛍️ Shopping</option>
                                        <option value="Medical">🏥 Medical</option>
                                        <option value="Other">📦 Other</option>
                                    </select>
                                </div>
                                <div className={styles.inputGroup}>
                                    <label>Amount ($)</label>
                                    <input type="number" step="any" placeholder="150" {...registerExpense("amount", { required: true })} />
                                </div>
                                <div className={styles.inputGroup}>
                                    <label>Date</label>
                                    <input type="date" defaultValue={new Date().toISOString().split("T")[0]} {...registerExpense("date")} />
                                </div>
                                <div className={styles.inputGroup}>
                                    <label>Description / Note</label>
                                    <input type="text" placeholder="Lunch at beach restaurant" {...registerExpense("description")} />
                                </div>
                                <div className={styles.fullWidth} style={{ display: "flex", justifyContent: "flex-end" }}>
                                    <button type="submit" className={styles.saveBtn} style={{ marginTop: "0" }} disabled={addingExp}>
                                        {addingExp ? "Adding..." : "+ Add Expense"}
                                    </button>
                                </div>
                            </form>
                        )}

                        {/* Expense entries list */}
                        <div className={styles.expenseList}>
                            <h3>Expense Log ({expenses.length})</h3>
                            {expenses.length > 0 ? (
                                expenses.map((exp) => (
                                    <div className={styles.expenseItem} key={exp._id}>
                                        <div className={styles.expenseDetails}>
                                            <h4>{exp.category === "Food" ? "🍽️ Food" :
                                                exp.category === "Hotel" ? "🏨 Hotel" :
                                                exp.category === "Fuel" ? "⛽ Fuel" :
                                                exp.category === "Shopping" ? "🛍️ Shopping" :
                                                exp.category === "Medical" ? "🏥 Medical" : "📦 Other"}</h4>
                                            <p>{exp.description ? `${exp.description} • ` : ""}{new Date(exp.date).toLocaleDateString()}</p>
                                        </div>
                                        <div className={styles.expenseAmount}>
                                            <span>${exp.amount.toLocaleString()}</span>
                                            {isOwner && (
                                                <button onClick={() => handleRemoveExpense(exp._id)} className={styles.removeExpBtn} title="Delete">
                                                    <FaTrash />
                                                </button>
                                            )}
                                        </div>
                                    </div>
                                ))
                            ) : (
                                <p style={{ color: "var(--subText)", textAlign: "center", marginTop: "15px" }}>No expenses recorded yet.</p>
                            )}
                        </div>
                    </div>

                    {/* 4. Reviews Module (Public trips only) */}
                    {trip.isPublic && (
                        <div className={styles.card}>
                            <h2>⭐ Reviews & Ratings</h2>

                            {/* Submit review */}
                            <form onSubmit={handleSubmitReview(handleAddReview)} className={styles.reviewForm}>
                                <label style={{ fontWeight: "500" }}>Leave a Review</label>
                                <div className={styles.ratingSelect}>
                                    {[1, 2, 3, 4, 5].map((star) => (
                                        <FaStar
                                            key={star}
                                            className={`${styles.star} ${star <= newRating ? styles.starSelected : ""}`}
                                            onClick={() => setNewRating(star)}
                                        />
                                    ))}
                                </div>
                                <textarea
                                    placeholder="Write a comment about this itinerary..."
                                    className={styles.reviewTextarea}
                                    {...registerReview("comment", { required: true })}
                                />
                                <button type="submit" className={styles.saveBtn} style={{ alignSelf: "flex-end", marginTop: "0" }}>
                                    Submit Review
                                </button>
                            </form>

                            {/* Reviews list */}
                            <div className={styles.activityList}>
                                {reviews.length > 0 ? (
                                    reviews.map((rev) => (
                                        <div className={styles.reviewItem} key={rev._id}>
                                            <div className={styles.reviewHeader}>
                                                <div className={styles.reviewerInfo}>
                                                    <img
                                                        src={rev.user.avatar || "https://cdn-icons-png.flaticon.com/512/3135/3135715.png"}
                                                        alt="Avatar"
                                                        className={styles.reviewerAvatar}
                                                    />
                                                    <div>
                                                        <span className={styles.reviewerName}>{rev.user.fullName}</span>
                                                    </div>
                                                </div>
                                                <div className={styles.reviewRating}>
                                                    <FaStar /> {rev.rating}/5
                                                </div>
                                            </div>
                                            <p className={styles.reviewComment}>{rev.comment}</p>
                                        </div>
                                    ))
                                ) : (
                                    <p style={{ color: "var(--subText)", textAlign: "center", marginTop: "15px" }}>
                                        No reviews on this trip yet. Be the first to leave one!
                                    </p>
                                )}
                            </div>
                        </div>
                    )}
                </div>

                {/* Right side: Weather Module widget */}
                <div>
                    <div className={styles.card}>
                        <h2>
                            <FaCloudSun /> Weather Tracker
                        </h2>
                        {weatherLoading ? (
                            <p style={{ color: "var(--subText)", textAlign: "center" }}>
                                Loading weather information...
                            </p>
                        ) : weather ? (
                            <div>
                                <div className={styles.weatherContainer}>
                                    <div className={styles.weatherMain}>
                                        <span className={styles.weatherTemp}>{weather.temperature}°C</span>
                                    </div>
                                    <div className={styles.weatherMetrics}>
                                        <div>Humidity: <b>{weather.humidity}%</b></div>
                                        <div>Wind: <b>{weather.wind} km/h</b></div>
                                    </div>
                                </div>
                                <div style={{ textTransform: "capitalize", color: "var(--subText)", marginBottom: "20px", fontSize: "14px" }}>
                                    Current Condition: <b>{weather.description}</b>
                                </div>

                                <div className={styles.forecastGrid}>
                                    {weather.forecast && weather.forecast.length > 0 ? (
                                        weather.forecast.map((fc, idx) => (
                                            <div className={styles.forecastDay} key={idx}>
                                                <h5>{fc.day}</h5>
                                                <p>{fc.temp}°</p>
                                                <span style={{ fontSize: "10px", color: "var(--subText)" }}>{fc.condition}</span>
                                            </div>
                                        ))
                                    ) : (
                                        <p style={{ gridColumn: "span 5", fontSize: "12px", color: "var(--subText)" }}>
                                            Forecast details not available.
                                        </p>
                                    )}
                                </div>
                            </div>
                        ) : (
                            <p style={{ color: "var(--subText)", textAlign: "center" }}>
                                ⚠️ Weather data is currently unavailable for {trip.city}.
                            </p>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default TripDetails;
